SELECT div.*
FROM declare_indicator_value div
INNER JOIN declare_indicator di ON div.indicator_id = di.id
WHERE div.business_type = #{businessType}
  AND div.business_id = #{businessId}
  AND di.group_id = #{groupId}

SELECT div.*
FROM declare_indicator_value div
WHERE div.business_type = #{businessType}
  AND div.business_id = #{businessId}
  AND div.indicator_code IN

    #{code}

SELECT div.*
FROM declare_indicator_value div
WHERE div.business_type = #{businessType}
  AND div.business_id = #{businessId}
  AND div.value_type = 12

    AND div.indicator_code = #{indicatorCode}

  AND JSON_CONTAINS(div.value_str, #{jsonFieldValue}, CONCAT('$.', #{fieldCode}))

SELECT COALESCE(SUM(JSON_LENGTH(div.value_str)), 0)
FROM declare_indicator_value div
WHERE div.business_type = #{businessType}
  AND div.business_id = #{businessId}
  AND div.value_type = 12

    AND div.indicator_code = #{indicatorCode}

SELECT div.*
FROM declare_indicator_value div
WHERE div.business_type = #{businessType}
  AND div.business_id = #{businessId}
  AND div.value_type = 12

    AND div.indicator_code = #{indicatorCode}
